  5	import { S3Commands } from '@odf/shared/s3';
  6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  7	import { TFunction } from 'react-i18next';
  8	import { useNavigate } from 'react-router-dom-v5-compat';
  9	import {
 10	  Modal,
 11	  ModalVariant,
 12	  Button,
 13	  ButtonVariant,
 14	  Alert,
 15	  AlertVariant,
 16	  TextInput,
 17	  TextInputTypes,
 18	  FormGroup,
 19	  FormHelperText,
 20	  HelperText,
 21	  HelperTextItem,
 22	  ValidatedOptions,
 23	} from '@patternfly/react-core';
 24	import {
 25	  getBucketOverviewBaseRoute,
 26	  DELIMITER,
 27	  PREFIX,
 28	} from '../../../constants';
 29	import { getPrefix, getEncodedPrefix } from '../../../utils';
 30	
 31	type CreateFolderModalProps = {
 32	  foldersPath: string;
 33	  bucketName: string;
 34	  s3Client: S3Commands;
 35	};
 36	
 37	const getValidations = (
 38	  isExisting: boolean,
 39	  containsForwardSlash: boolean,
 40	  folderName: string,
 41	  t: TFunction
 42	): [ValidatedOptions, string] => {
 43	  if (isExisting)
 44	    return [
 45	      ValidatedOptions.error,
 46	      t(
 47	        'This name is already in use. Try using a different name for your folder.'
 48	      ),
 49	    ];
 50	  else if (containsForwardSlash)
 51	    return [
 52	      ValidatedOptions.error,
 53	      t('The forward slash ("/") cannot be used.'),
 54	    ];
 55	  else if (!!folderName)
 56	    return [
 57	      ValidatedOptions.success,
 58	      t('All characters are allowed except for the forward slash ("/").'),
 59	    ];
 60	  else
 61	    return [
 62	      ValidatedOptions.default,
 63	      t(
 64	        'A unique folder name is required. All characters are allowed except for the forward slash ("/").'
 65	      ),
 66	    ];
 67	};
 68	
 69	const CreateFolderModal: React.FC<CommonModalProps<CreateFolderModalProps>> = ({
 70	  closeModal,
 71	  isOpen,
 72	  extraProps: { foldersPath, bucketName, s3Client },
 73	}) => {
 74	  const { t } = useCustomTranslation();
 75	
 76	  const navigate = useNavigate();
 77	
 78	  const [folderName, setFolderName] = React.useState<string>('');
 79	  const [inProgress, setInProgress] = React.useState<boolean>(false);
 80	  const [isExisting, setIsExisting] = React.useState<boolean>(false);
 81	  const [error, setError] = React.useState<Error>();
 82	
 83	  const containsForwardSlash = folderName.includes(DELIMITER);
 84	  const [validationVariant, helperText] = getValidations(
 85	    isExisting,
 86	    containsForwardSlash,
 87	    folderName,
 88	    t
 89	  );
 90	  const providerType = s3Client.providerType as S3ProviderType;
 91	
 92	  const onCreate = async (event) => {
 93	    event.preventDefault();
 94	    setInProgress(true);
 95	
 96	    try {
 97	      const folderNameWDelimiter = folderName + DELIMITER;
 98	      const data = await s3Client.listObjects({
 99	        Bucket: bucketName,
100	        MaxKeys: 1,
101	        Delimiter: DELIMITER,
102	        Prefix: getPrefix(folderNameWDelimiter, foldersPath),
103	      });
104	
105	      const doesFolderAlreadyExist =
106	        !!data?.Contents?.length || !!data?.CommonPrefixes?.length;
107	
108	      if (doesFolderAlreadyExist) {
109	        setInProgress(false);
110	        setIsExisting(true);
111	      } else {
112	        const prefix = getEncodedPrefix(folderNameWDelimiter, foldersPath);
113	        navigate(
114	          `${getBucketOverviewBaseRoute(bucketName, providerType)}?${PREFIX}=${prefix}`
115	        );
116	        closeModal();
117	      }
118	    } catch (err) {
119	      setInProgress(false);
120	      setError(err);
121	    }
122	  };
123	
124	  return (
125	    <Modal
126	      title={t('Create folder')}
127	      isOpen={isOpen}
128	      onClose={closeModal}
129	      description={
130	        <div className="text-muted">
131	          {t(
132	            'Organize objects within a bucket by creating virtual folders for easier management and navigation of objects.'
133	          )}
134	        </div>
135	      }
136	      variant={ModalVariant.medium}
137	      actions={[
138	        <ButtonBar
139	          inProgress={inProgress}
140	          errorMessage={error?.message || JSON.stringify(error)}
141	        >
142	          <span>
143	            <Button
144	              variant={ButtonVariant.primary}
145	              onClick={onCreate}
146	              isDisabled={!folderName || containsForwardSlash || !!error}
147	              className="pf-v6-u-mr-xs"
148	            >
149	              {t('Create')}
150	            </Button>
151	            <Button
152	              variant={ButtonVariant.secondary}
153	              onClick={closeModal}
154	              className="pf-v6-u-ml-xs"
155	            >
156	              {t('Cancel')}
157	            </Button>
158	          </span>
159	        </ButtonBar>,
160	      ]}
161	    >
162	      <Alert
163	        variant={AlertVariant.info}
164	        className="pf-v6-u-mb-sm"
165	        isInline
166	        title={t(
167	          'Folders help structure and group objects logically by using prefixes in object keys, without enforcing any physical hierarchy.'
168	        )}
169	      />
170	      <FormGroup label={t('Folder name')} fieldId="folder-name" isRequired>
171	        <TextInput
172	          value={folderName}
173	          id="folder-name"
174	          onChange={(_event, value) => {
175	            setFolderName(value);
176	            setIsExisting(false);
177	          }}
178	          isRequired
179	          validated={validationVariant}
180	          type={TextInputTypes.text}
181	        />
182	        <FormHelperText>
183	          <HelperText>
184	            <HelperTextItem variant={validationVariant}>
185	              {helperText}
186	            </HelperTextItem>
187	          </HelperText>
188	        </FormHelperText>
189	      </FormGroup>
190	    </Modal>
191	  );
192	};
193	
194	export default CreateFolderModal;

